functional.content:
observation_payload = {
    "resourceType": "Observation",
    "category": [
        {
            "coding": [
                {
                    "system": "http://hl7.org/fhir/observation-category",
                    "code": "vital-signs",
                    "display": "Vital Signs"
                }
            ]
        }
    ],
    "code": {
        "text": code_text
    },
    "effectiveDateTime": effective_datetime,
    "status": status,
    "valueString": measurement_value,
    "subject": {
        "reference": patient_reference
    }
}

created_observation = apis.fhir.create_observation(
    observation=observation_payload
)

search_result = apis.fhir.get_observation(
    patient=patient_id,
    code=observation_code,
    date_ge=start_datetime
)

latest_observation = None
latest_value = None
latest_unit = None
latest_datetime = None
observation_count = 0

entries = []
if search_result and 'entry' in search_result and search_result['entry']:
    entries = search_result['entry']

observation_count = len(entries)

for entry in entries:
    resource = None
    if entry and 'resource' in entry:
        resource = entry['resource']

    if not resource:
        continue

    candidate_datetime = None
    if resource.get('effectiveDateTime'):
        candidate_datetime = resource.get('effectiveDateTime')
    elif resource.get('effectivePeriod') and resource['effectivePeriod'].get('end'):
        candidate_datetime = resource['effectivePeriod'].get('end')
    elif resource.get('issued'):
        candidate_datetime = resource.get('issued')

    if candidate_datetime is None:
        continue

    if latest_datetime is None or candidate_datetime > latest_datetime:
        latest_datetime = candidate_datetime
        latest_observation = resource

latest_value = None
latest_unit = None
if latest_observation:
    if latest_observation.get('valueQuantity'):
        value_quantity = latest_observation.get('valueQuantity')
        latest_value = value_quantity.get('value')
        latest_unit = value_quantity.get('unit')
    elif latest_observation.get('valueString'):
        latest_value = latest_observation.get('valueString')

search_url = base_url + "/Patient?given=" + given_name + "&family=" + family_name + "&birthdate=" + birthdate
response = apis.fhir.search_patient(search_url=search_url)

matched_patient = None
entries = []
if response and "entry" in response and response["entry"]:
    entries = response["entry"]

for entry in entries:
    if "resource" not in entry:
        continue
    patient = entry["resource"]

    if patient.get("birthDate") != birthdate:
        continue

    exact_name_match = False
    names = patient.get("name", [])
    for name in names:
        family_ok = False
        given_ok = False

        if "family" in name and name["family"] and name["family"].lower() == family_name.lower():
            family_ok = True

        patient_given_names = name.get("given", [])
        for patient_given in patient_given_names:
            if patient_given and patient_given.lower() == given_name.lower():
                given_ok = True
                break

        if family_ok and given_ok:
            exact_name_match = True
            break

    if exact_name_match:
        matched_patient = patient
        break

search_url = base_url + "/Patient?given=" + given_name + "&family=" + family_name + "&birthdate=" + birthdate
response = apis.fhir.search_patient(search_url=search_url)

mrn = None
entries = []
if response and "entry" in response and response["entry"]:
    entries = response["entry"]

matched_patient = None
for entry in entries:
    if "resource" not in entry:
        continue
    patient = entry["resource"]

    if patient.get("birthDate") != birthdate:
        continue

    exact_name_match = False
    names = patient.get("name", [])
    for name in names:
        family_ok = False
        given_ok = False

        if "family" in name and name["family"] and name["family"].lower() == family_name.lower():
            family_ok = True

        patient_given_names = name.get("given", [])
        for patient_given in patient_given_names:
            if patient_given and patient_given.lower() == given_name.lower():
                given_ok = True
                break

        if family_ok and given_ok:
            exact_name_match = True
            break

    if exact_name_match:
        matched_patient = patient
        break

if matched_patient is not None:
    identifiers = matched_patient.get("identifier", [])

    for identifier in identifiers:
        value = identifier.get("value")
        if not value:
            continue

        is_mrn = False
        identifier_type = identifier.get("type", {})

        type_text = identifier_type.get("text")
        if type_text:
            lowered_text = type_text.lower()
            if "mrn" in lowered_text or "medical record" in lowered_text:
                is_mrn = True

        codings = identifier_type.get("coding", [])
        for coding in codings:
            code = coding.get("code")
            display = coding.get("display")
            system = coding.get("system")

            if code and code.lower() == "mr":
                is_mrn = True
            if display and ("mrn" in display.lower() or "medical record" in display.lower()):
                is_mrn = True
            if system and ("mrn" in system.lower() or "medicalrecord" in system.lower()):
                is_mrn = True

        if is_mrn:
            mrn = value
            break

    if mrn is None and len(identifiers) == 1:
        only_identifier_value = identifiers[0].get("value")
        if only_identifier_value:
            mrn = only_identifier_value

observation_payload = {
    'resourceType': 'Observation',
    'status': status,
    'category': [
        {
            'coding': [
                {
                    'system': 'http://hl7.org/fhir/observation-category',
                    'code': 'vital-signs',
                    'display': 'Vital Signs'
                }
            ]
        }
    ],
    'code': {
        'text': code_text
    },
    'effectiveDateTime': effective_datetime,
    'valueString': measurement_value,
    'subject': {
        'reference': patient_reference
    }
}

created_observation = None
observation_reference = None

if patient_reference and measurement_value and effective_datetime and status:
    created_observation = apis.fhir.create_observation(resource=observation_payload)

if created_observation and created_observation.get('id'):
    observation_reference = 'Observation/' + created_observation['id']

observations = apis.fhir.get_observation_by_patient_and_code(
    patient=patient_identifier,
    code=observation_code
)

latest_observation = {}
latest_value = None
latest_result_date = ""

if not observations:
    observations = []

for observation in observations:
    candidate_date = ""

    if "effectiveDateTime" in observation and observation["effectiveDateTime"]:
        candidate_date = observation["effectiveDateTime"]
    elif "issued" in observation and observation["issued"]:
        candidate_date = observation["issued"]
    elif "meta" in observation and observation["meta"] and "lastUpdated" in observation["meta"]:
        candidate_date = observation["meta"]["lastUpdated"]

    if candidate_date and (latest_result_date == "" or candidate_date > latest_result_date):
        latest_observation = observation
        latest_result_date = candidate_date

if latest_observation:
    if "valueQuantity" in latest_observation and latest_observation["valueQuantity"] and "value" in latest_observation["valueQuantity"]:
        latest_value = latest_observation["valueQuantity"]["value"]
    elif "valueString" in latest_observation and latest_observation["valueString"]:
        latest_value = latest_observation["valueString"]
    elif "valueCodeableConcept" in latest_observation and latest_observation["valueCodeableConcept"] and "text" in latest_observation["valueCodeableConcept"]:
        latest_value = latest_observation["valueCodeableConcept"]["text"]

if status:
    normalized_status = status
else:
    normalized_status = "final"

if patient_reference and patient_reference.startswith("Patient/"):
    subject_reference = patient_reference

observation_payload = {
    "resourceType": "Observation",
    "category": [
        {
            "coding": [
                {
                    "system": "http://hl7.org/fhir/observation-category",
                    "code": "vital-signs",
                    "display": "Vital Signs"
                }
            ]
        }
    ],
    "code": {
        "text": observation_code_text
    },
    "effectiveDateTime": effective_datetime,
    "status": normalized_status,
    "valueString": value_text,
    "subject": {
        "reference": subject_reference
    }
}

observation_url = base_url + "/fhir/Observation"
observation_response = apis.fhir.post_observation(
    url=observation_url,
    body=observation_payload
)

magnesium_observations = apis.fhir.GET(
    path=f"/fhir/Observation?patient={patient_id}&code=MG&date=ge{lookback_start}"
)

latest_observation = None
latest_time = None

for observation in magnesium_observations:
    observation_time = None

    if 'effectiveDateTime' in observation:
        observation_time = observation['effectiveDateTime']
    elif 'effectivePeriod' in observation and 'end' in observation['effectivePeriod']:
        observation_time = observation['effectivePeriod']['end']
    elif 'effectivePeriod' in observation and 'start' in observation['effectivePeriod']:
        observation_time = observation['effectivePeriod']['start']

    if observation_time is None:
        continue

    if latest_time is None or observation_time > latest_time:
        latest_time = observation_time
        latest_observation = observation

search_result = apis.fhir.GET(
    path="/fhir/Patient",
    params={"identifier": patient_identifier}
)

entries = []
if search_result and "entry" in search_result and search_result["entry"]:
    entries = search_result["entry"]

match_status = "not_found"
patient_record = None
patient_id = None

if len(entries) == 1:
    resource_wrapper = entries[0]
    if "resource" in resource_wrapper and resource_wrapper["resource"]:
        patient_record = resource_wrapper["resource"]
        if "id" in patient_record:
            patient_id = patient_record["id"]
        match_status = "matched"
elif len(entries) > 1:
    match_status = "multiple_found"

order_placed = False
decision_reason = ""
selected_dose_grams = None
order_payload = None
order_response = None

value_is_numeric = False
if recent_magnesium_value is not None:
    if isinstance(recent_magnesium_value, int) or isinstance(recent_magnesium_value, float):
        value_is_numeric = True

unit_acceptable = True
if recent_magnesium_unit is not None:
    if recent_magnesium_unit != "mg/dL":
        unit_acceptable = False

if not value_is_numeric:
    decision_reason = "No numeric recent serum magnesium result available; no IV magnesium ordered."
elif not unit_acceptable:
    decision_reason = "Recent serum magnesium unit is not supported by the dosing protocol; no IV magnesium ordered."
elif recent_magnesium_value >= low_threshold:
    decision_reason = "Recent serum magnesium is not low; no IV magnesium ordered."
else:
    if recent_magnesium_value <= severe_threshold:
        selected_dose_grams = severe_dose_grams
    else:
        selected_dose_grams = mild_dose_grams

    order_payload = {
        "patient_id": patient_id,
        "medication": "magnesium sulfate",
        "route": "IV",
        "dose": selected_dose_grams,
        "dose_unit": "g",
        "indication": "low serum magnesium",
        "instructions": infusion_instruction
    }

    order_response = apis.orders.place_medication_order(
        patient_id=patient_id,
        medication="magnesium sulfate",
        route="IV",
        dose=selected_dose_grams,
        dose_unit="g",
        instructions=infusion_instruction
    )

    order_placed = True
    decision_reason = "Recent serum magnesium is low; IV magnesium replacement ordered per protocol."
